            {"q_en": "Which movement was launched on 8 Aug 1942?", "q_hi": "8 अगस्त 1942 को कौन सा आंदोलन?", "options_en": ["Salt March","Quit India","Khilafat","Swadeshi"], "options_hi": ["नमक यात्रा","भारत छोड़ो","ख़िलाफ़त","स्वदेशी"], "answer": 1},
            {"q_en": "What award did she receive (posthumously)?", "q_hi": "उन्हें कौन सा सम्मान मरणोपरांत मिला?", "options_en": ["Padma Shri","Bharat Ratna","Param Vir","Kirti Chakra"], "options_hi": ["पद्म श्री","भारत रत्न","परम वीर","कीर्ति चक्र"], "answer": 1},
            {"q_en": "She became Delhi's first elected what?", "q_hi": "वे दिल्ली की पहली निर्वाचित क्या बनीं?", "options_en": ["MP","Mayor","Governor","CM"], "options_hi": ["सांसद","मेयर","राज्यपाल","मुख्यमंत्री"], "answer": 1},
            {"q_en": "What underground magazine did she edit?", "q_hi": "उन्होंने कौन सी भूमिगत पत्रिका संपादित की?", "options_en": ["Kesari","Inquilab","Hindu","Pioneer"], "options_hi": ["केसरी","इंक़लाब","हिंदू","पायनियर"], "answer": 1},
